INSERT INTO public.photos VALUES (22772, 'Pl. de las Canteras 1971', 'Imagen capturada en la terminal de la lâ”œآ،nea 5 "Venecia-Delicias" ubicada en la plaza de las Canteras, con la composiciâ”œâ”‚n M+R 109 en posiciâ”œâ”‚n descanso. Tras ella, edificios del principio de la calle de Alicante (antigua de Larraz), luego derribados y sustituidos por bloques mâ”œأ­s modernos, si bien no tan verticales como el que ya se alzaba a su derecha, esquinero con el arranque de la calle Fray Juliâ”œأ­n Garcâ”œآ®s, de la que era su nâ”¬â•‘ 2-4. Al fondo, a la derecha, edificios de la avenida de Amâ”œآ®rica. A finales de este aâ”œâ–’o de 1971, la lâ”œآ،nea 5 fue suprimida, y esta unidad, en servicio desde 1944, pasâ”œâ”‚ a otras funciones, hasta 1976, cuando el cierre de la â”œâ•‘ltima lâ”œآ،nea. Fuente visual: foto Josâ”œآ® Marâ”œآ،a Valero', 1971, 1971, 1971, 'Anos 70', 'TORRERO', 41.63168500, -0.88607100, '0101000020E610000076E3DD91B15AECBFD72FD80DDBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33659395855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33659395855.webp', 'https://www.flickr.com/photos/zaragozaantigua/33659395855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22817, 'Calle de â”œأ¼frica 1974', 'Inâ”œآ®dita imagen capturada en la calle de â”œأ¼frica y centrada en el chaflâ”œأ­n ocupado por el bar El Pinar junto a las viviendas mancomunadas construidas entre esta calle y la del Tiro, que se abre a la izquierda. A la derecha, pinos en la margen derecha del Canal Imperial de Aragâ”œâ”‚n. Mâ”œأ­s adelante y a la izquierda, principio de las calles de Jaâ”œآ®n y de Roger de Lauria, en torno a las cuales perduraban las originales parcelas de esta zona del barrio de Venecia, salvo el mâ”œأ­s reciente inmueble del nâ”¬â•‘ 21, y el modernâ”œآ،simo bloque del nâ”¬â•‘ 1 de la calle del Pinar, al fondo. En el momento de tomar esta fotografâ”œآ،a este veterano barrio surgido entre la avenida de Amâ”œآ®rica y el Canal contaba con unas 6.000 familias, y la Asociaciâ”œâ”‚n de Cabezas de Familia se esforzaba por reivindicar servicios pâ”œâ•‘blicos como una guarderâ”œآ،a infantil (ninguna en el barrio), un "club" de jubilados (ninguno en el barrio), y un centro cultural (ninguno en el barrio). De la pavimentaciâ”œâ”‚n de las calles, terrosas como ilustra la imagen, ni se hablaba. Mientras tanto, el câ”œآ®ntrico paseo de Marina Moreno estaba siendo "embellecido"...', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.63156200, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBCB20B06D7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51601889686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51601889686.webp', 'https://www.flickr.com/photos/zaragozaantigua/51601889686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22822, 'Barrio de Begoâ”œâ–’a 1974', 'Inâ”œآ®dita imagen capturada desde el paseo del Canal y orientada hacia la margen derecha del Canal Imperial de Aragâ”œâ”‚n (visible en primer tâ”œآ®rmino), donde desde mediados de los aâ”œâ–’os 50 se levantâ”œâ”‚ el "nuevo barrio de N.â”¬آ¬ S.â”¬آ¬ de Begoâ”œâ–’a" vertebrado entre las calles de Sancho Ramâ”œآ،rez y Lasierra Purroy, ademâ”œأ­s de dos nuevas calles sin nombre denominadas "A" (actual de N.â”¬آ¬ S.â”¬آ¬ de Monlora) y "D" (actual del Doctor Pascual Oliver). A la derecha, vista de las fincas 2, 3, 6, 7 y 8 de este "barrio" vertebradas en torno a la referida calle "A". Delante de ellas, una "pluma" de obra anuncia la pronta construcciâ”œâ”‚n de los mâ”œأ­s modernos bloques recayentes a la calle "B" (actual de Honorio Garcâ”œآ،a Condoy") y a la de Sancho Ramâ”œآ،rez. Al fondo destaca la gran grada de cemento del veterano campo de Torrero construida en 1943, y tras ella algunos edificios de vivienda de la calle de Monzâ”œâ”‚n a la altura de la calle del Râ”œآ،o Jalâ”œâ”‚n.', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.63177100, -0.88346600, '0101000020E61000000D18247D5A45ECBFD6C743DFDDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51638184775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51638184775.webp', 'https://www.flickr.com/photos/zaragozaantigua/51638184775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22829, 'Campo de Torrero 1973', 'Imagen capturada desde la grada norte del campo de fâ”œâ•‘tbol de Torrero y centrada en la antigua piscina en desuso situada junto a â”œآ®l. Hacia el fondo, edificios del entorno de la calle de Santa Gema, al otro lado del Canal Imperial de Aragâ”œâ”‚n. Poco despuâ”œآ®s el terreno de la piscina serâ”œآ،a reurbanizado para dar paso a un nuevo vial entre el campo y el barrio de N.â”¬آ¬ S.â”¬آ¬ de Begoâ”œâ–’a, que queda justo a la izquierda y fuera de plano.', 1973, 1973, 1973, 'Anos 70', 'TORRERO', 41.63091300, -0.88397000, '0101000020E6100000D3A414747B49ECBF85CFD6C1C1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53531400662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53531400662.webp', 'https://www.flickr.com/photos/zaragozaantigua/53531400662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22973, 'Avenida Amâ”œآ®rica 1997', '1997. Concentraciâ”œâ”‚n en la puerta de la câ”œأ­rcel de Torrero en protesta por la muerte en su interior de un insumiso preso, Kike Mur, que hoy da nombre al Centro Social Okupado que utiliza el edificio administrativo de la antigua prisiâ”œâ”‚n. Fuente: Zaragoza Rebelde', 1997, 1997, 1997, 'Anos 90', 'TORRERO', 41.62756900, -0.88658700, '0101000020E61000004CE141B3EB5EECBFE17D552E54D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15016754711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15016754711.webp', 'https://www.flickr.com/photos/zaragozaantigua/15016754711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23635, 'Eloy Fernâ”œأ­ndez Clemente 1975', 'En junio de 1975 Eloy Fernâ”œأ­ndez Clemente, en su calidad de director de la revista "Andalâ”œأ­n", fue ingresado preso en la câ”œأ­rcel de Torrero durante una semana. Desde sus comienzos, esta revista habâ”œآ،a sufrido numerosos avatares: secuestros (en 1974 se retirâ”œâ”‚ el nâ”œâ•‘mero dedicado al derrocamiento de Allende; igual suerte corriâ”œâ”‚ el dossier sobre la batalla de Teruel, o el cartel del Gobernador Civil de Huesca con casco prusiano), expedientes, declaraciones en el juzgado, presiones policiales, boicots econâ”œâ”‚micos... Entre las personalidades que intervinieron para pedir la libertad del director de la revista, llamâ”œâ”‚ la atenciâ”œâ”‚n la del arzobispo Cantero Cuadrado, que se ofreciâ”œâ”‚ para mediar ante las autoridades civiles. No fue aceptado este gesto, y la condena fue cumplida. En la imagen, Eloy Fernâ”œأ­ndez Clemente con su compaâ”œâ–’era, ademâ”œأ­s de amigos y amigas del entorno de "Andalâ”œأ­n", a la salida de la câ”œأ­rcel de Torrero.', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.62743600, -0.88681700, '0101000020E6100000BA2D910BCE60ECBFA22AA6D24FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14807693009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14807693009.webp', 'https://www.flickr.com/photos/zaragozaantigua/14807693009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23638, 'Câ”œأ­rcel de Torrero 1977', 'Foto: Arturo Burgos. "Sobre las seis de la tarde del dâ”œآ،a 19 de Julio de 1977 unos cuarenta presos comunes se subieron al tejado de uno de los pabellones con pancartas en las que pedâ”œآ،an Amnistâ”œآ،a y Libertad. Permanecieron en el tejado durante toda la noche y al mediodâ”œآ،a siguiente depusieron la protesta. Igualmente hubo motines en otras câ”œأ­rceles del estado, como Carabanchel y Puerto de Santa Marâ”œآ،a, donde hubo un muerto. Aquel dâ”œآ،a hubo una autâ”œآ®ntica batalla campal entre las fuerzas antidisturbios y los vecinos del barrio y de otras zonas de Zaragoza que subâ”œآ،an a Torrero a demostrar su solidaridad con los presos. Aquella tarde-noche fueron frecuentes las carreras, las cargas policiales que dispararon pelotas de goma, mientras los ciudadanos se defendâ”œآ،an de â”œآ®stos tirâ”œأ­ndoles piedras. Todas las calles cercanas a la prisiâ”œâ”‚n estaban tomadas por los grises, resultando heridos de pelotas de goma algunos jâ”œâ”‚venes. Estas manifestaciones fueron convocadas por la COPEL (Coordinadora de Presos en Lucha)." Del libro "Torrero. Un paseo por el recuerdo". Transcrito por Raâ”œâ•‘l Bernal. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62757800, -0.88677200, '0101000020E6100000BB4560AC6F60ECBF34D8D47954D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15103438336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15103438336.webp', 'https://www.flickr.com/photos/zaragozaantigua/15103438336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23642, 'Misa en Torrero 1940', 'Archivo Municipal. Gerardo Sancho Ramo. 1940. "Misa en la Prisiâ”œâ”‚n Provincial de Torrero." Imagen de una de las "Comuniones Pascuales" impartidas con un carâ”œأ­cter voluntariamente obligatorio, en las que por medio de sermones sacerdotales se buscaba la re-catolizaciâ”œâ”‚n y re-ideologizaciâ”œâ”‚n de los presos. Tras el sermâ”œâ”‚n, la comuniâ”œâ”‚n, el himno nacional musicado, y nutridos vivas a Espaâ”œâ–’a y al Generalâ”œآ،simo. Al sonar la mâ”œâ•‘sica los reclusos tenâ”œآ،an que saludar con la mano derecha levantada y bien abierta, realizando el saludo fascista, y vitorear tres veces a Franco. Despuâ”œآ®s de esto, los presos eran أ”أ‡آ£recompensadosأ”أ‡أک con una raciâ”œâ”‚n doble de rancho. Desde julio de 1936, hasta setiembre de 1945, (dâ”œآ،as despuâ”œآ®s de la firma de la rendiciâ”œâ”‚n incondicional del Japâ”œâ”‚n), el saludo fascista fue obligatorio en todos los actos sociales pâ”œâ•‘blicos, institucionales, etc, de la Espaâ”œâ–’a franquista. Las câ”œأ­rceles no fueron una excepciâ”œâ”‚n, ya fuera el penado "comâ”œâ•‘n", o "polâ”œآ،tico". El saludo perdurâ”œâ”‚ hasta dâ”œآ®cadas despuâ”œآ®s, y mâ”œأ­s.', 1940, 1940, 1940, 'Anos 40', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15711127491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15711127491.webp', 'https://www.flickr.com/photos/zaragozaantigua/15711127491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23655, 'Polvorines Torrero 1895', '"LA CATâ”œأ¼STROFE DE ZARAGOZA. Honda consternaciâ”œâ”‚n causâ”œâ”‚ en toda Espaâ”œâ–’a la desgracia acaecida en la capital aragonesa el 23 del pasado (mes de febrero). Hallâ”œأ­banse cinco pobres muchachas descargando cartuchos en las cuevas prâ”œâ”‚ximas al polvorâ”œآ،n de Torrero, habilitadas para dicho objeto, cuando al terminar la faena, â”œأ­ eso de la una de la tarde, explotaron seis cajas de aquâ”œآ®llos, sistema Berdan. Habâ”œآ،a reventado un cartucho en manos de una de las infelices operarias, y prendiâ”œâ”‚ fuego en las cajas. Las vâ”œآ،ctimas, con los vestidos ardiendo, se lanzaron fuera de la cueva; al ruido de la explosiâ”œâ”‚n, acudieron los soldados que prestaban servicio en los puestos inmediatos, y socorrieron â”œأ­ las vâ”œآ،ctimas, al mismo tiempo que trataban de localizar el incendio, el cual, de haberse propagado â”œأ­ los polvorines inmediatos, hubiera causado estragos muchâ”œآ،simo mâ”œأ­s horribles aâ”œâ•‘n. Han fallecido ya tres mujeres, despuâ”œآ®s de agudâ”œآ،simos sufrimientos." Este dibujo ilustraba la noticia, referida a un accidente en los polvorines que el Ejâ”œآ®rcito tenâ”œآ،a al sur del cementerio de Torrero, en una zona de casi 13 hectâ”œأ­reas de extensiâ”œâ”‚n. Tras la "Operaciâ”œâ”‚n Cuarteles" de finales de los aâ”œâ–’os 70 del pasado siglo, el desalojo de estos polvorines sirviâ”œâ”‚ para ampliar el cementerio hasta el Barranco de la Muerte. Fuente: "La Ilustraciâ”œâ”‚n Ibâ”œآ®rica", Barcelona.', 1895, 1895, 1895, 'Siglo XIX', 'TORRERO', 41.61749500, -0.88884100, '0101000020E610000086014BAE6271ECBFC5387F130ACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20494670764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20494670764.webp', 'https://www.flickr.com/photos/zaragozaantigua/20494670764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23657, 'Câ”œأ­rcel de Torrero c.1970', 'Vista aâ”œآ®rea centrada en la Câ”œأ­rcel de Torrero de Zaragoza. Abajo, edificio de acceso por la avenida de Amâ”œآ®rica 109. Fue inaugurada en 1928 como Prisiâ”œâ”‚n Provincial y demolida parcialmente en 2005. Fuente visual: www.rolde.org/', 1970, 1970, 1970, 'Anos 70', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22141895038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22141895038.webp', 'https://www.flickr.com/photos/zaragozaantigua/22141895038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23660, 'Câ”œأ­rcel 2005', 'Comienzo de la demoliciâ”œâ”‚n de la câ”œأ­rcel de Torrero, dejando sâ”œâ”‚lo en pie el edificio de acceso, en julio de 2005. Fuente: Agencia EFE.', 2005, 2005, 2005, 'Siglo XXI', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24382413739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24382413739.webp', 'https://www.flickr.com/photos/zaragozaantigua/24382413739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23681, 'Canal Imperial c.1905', 'Inâ”œآ®dita imagen capturada a orillas del Canal Imperial tras el recto tramo de la Playa de Torrero, donde se desvâ”œآ،a bruscamente, casi 90 grados, y se encamina en paralelo al camino del Cabezo Cortado y de la quinta de Julieta Sagols. En primer tâ”œآ®rmino, algunas de las grandes barcazas de transporte canalino de mercancâ”œآ،as con un posado colectivo de sus manejadores, ademâ”œأ­s de algâ”œâ•‘n ocasional tancredo. Justo detrâ”œأ­s y en la margen derecha, choperas de los viveros del Canal. En la margen izquierda, de fondo, el paseo de la Playa de Torrero con algunos de los pabellones e instalaciones del Cuartel de Torrero, y de los talleres y almacenes del Canal Imperial. Se destaca por su altura y caracterâ”œآ،stica figura, entre los chopos, la câ”œâ•‘pula de la neoclâ”œأ­sica iglesia de San Fernando,', 1905, 1905, 1905, 'Anos 1900', 'TORRERO', 41.63235600, -0.88166300, '0101000020E6100000E3FBE2529536ECBFF6B6990AF1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48015320327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48015320327.webp', 'https://www.flickr.com/photos/zaragozaantigua/48015320327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24035, 'Cementerio 1943', 'El 21 de abril de 1943 tuvo lugar una bizarra escenificaciâ”œâ”‚n en el cementerio de Torrero, coincidiendo con la oficial celebraciâ”œâ”‚n fascista del "aniversario" de la fundaciâ”œâ”‚n de la ciudad de Roma, en tiempos en que las cosas imperiales estaban muy en boga en ambos paâ”œآ،ses. Estirando la visita a las obras del "Sacrario Militare" que entonces se estaba erigiendo en Cuâ”œآ®llar, como homenaje a los italianos "muertos en la Cruzada espaâ”œâ–’ola", tuvo lugar una visita al cementerio de la "Aviazione Legionaria" de Torrero, inaugurado en 1940, donde los generales Augusto Grassi (saludando, a la izquierda, sic), Arriani, y el coronel Carnevale, depositaron flores a sus paisanos fallecidos, oyeron misa, y estuvieron acompaâ”œâ–’ados de una nutrida comparsa de jerarcas y autoridades militares y civiles locales, algunas de las cuales fueron luego condecoradas como "caballeros de la orden de la Corona de Italia". En la imagen, parafernalia fascista del referido homenaje, bajo los estandartes de la Italia y Espaâ”œâ–’a del momento, ademâ”œأ­s de las de Falange, y los carlistas, en el legionario recinto habilitado en una parcela de la ampliaciâ”œâ”‚n de 1936 del cementerio. En 1946, cuando el contexto sociopolâ”œآ،tico italiano era uno muy distinto del de 1943, y acabado el nuevo-viejo "Sacrario Militare", comenzâ”œâ”‚ la inhumaciâ”œâ”‚n de los restos de esta parcela, y su traslado a Cuâ”œآ®llar. Extramuros del Sacrario, todo seguâ”œآ،a igual. Fuente visual: Archivo Municipal de Zaragoza.', 1943, 1943, 1943, 'Anos 40', 'TORRERO', 41.62312800, -0.88256300, '0101000020E6100000D61BB5C2F43DECBF679C86A8C2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29211917616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29211917616.webp', 'https://www.flickr.com/photos/zaragozaantigua/29211917616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24951, 'Puente nuevo sobre el Huerva 1928', 'Imagen capturada desde la prolongaciâ”œâ”‚n de la Gran Vâ”œآ،a poco antes de finalizar la obra de construcciâ”œâ”‚n del nuevo puente sobre el râ”œآ،o Huerva, que serâ”œآ،a inaugurado al aâ”œâ–’o siguiente con la presencia del dictador Primo de Rivera, por lo que el puente fue denominado del Trece de Septiembre (fecha del golpe de estado de 1923 encabezado por â”œآ®l con el consentimiento y respaldo del rey Alfonso XIII y del bloque hegemâ”œâ”‚nico de poder). Al fondo, el nuevo parque de Buenavista, y a la derecha, la chimenea de la fâ”œأ­brica de harinas la Imperial de Aragâ”œâ”‚n, junto al Canal Imperial. Fuente visual: Zaragoza, dos milenios de agua.', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.63730400, -0.89775100, '0101000020E610000004711E4E60BAECBF14CE6E2D93D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36591084032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36591084032.webp', 'https://www.flickr.com/photos/zaragozaantigua/36591084032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24943, 'Cabezo de Buenavista c.1920', 'Desde la altura del Cabezo de Buenavista, un vistazo en direcciâ”œâ”‚n a la zanja del râ”œآ،o Huerva y la antigua carretera de Zaragoza a Teruel, antes de que el previsto y nuevo parque de Buenavista fuera una realidad. Hasta entonces, entre el Huerva y el Cabezo, se extendâ”œآ،a un notable conjunto de huertas y campos de labor, apenas vertebrado por el Camino del Sâ”œأ­bado y el antiguo Camino de Cuarte, y estaba surcado por acequias fluyendo desde el Canal, como la de las Adulas, y riegos derivados y subsidiarios de ella, como el del Tuerto, y el de Fortea. Al fondo, despuntan elevados los macizos pabellones seriados del "Manicomio", en el Terminillo. Pocos aâ”œâ–’os despuâ”œآ®s, las expropiaciones y obras transformarâ”œآ،an este bucâ”œâ”‚lico lugar de forma destacada, convirtiâ”œآ®ndolo en el humanizado Parque Buenavista. Fuente visual: Archivo fotogrâ”œأ­fico histâ”œâ”‚rico del SIPA (DARA-AHPZ).', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.63359100, -0.89335200, '0101000020E61000003F1EFAEE5696ECBF1D05888219D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23995412136.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23995412136.webp', 'https://www.flickr.com/photos/zaragozaantigua/23995412136/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24092, 'Cabezo de Buenavista 1985', 'Imagen capturada en el Cabezo de Buenavista del Parque de Primo de Rivera durante la inauguraciâ”œâ”‚n del "Monumento a los aragoneses en campos de concentraciâ”œâ”‚n alemanes" el 22 de septiembre de 1985. Con motivo de la celebraciâ”œâ”‚n de la asamblea anual de la "Amical de Mauthausen" en Zaragoza, se organizaron varias actividades vinculadas con la entonces minoritaria reivindicaciâ”œâ”‚n de la Memoria histâ”œâ”‚rica vinculada a este atroz episodio de la represiâ”œâ”‚n nazi-fascista: la exposiciâ”œâ”‚n "Exilio y Deportaciâ”œâ”‚n" en dependencias de la DPZ, una recepciâ”œâ”‚n oficial del presidente de la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n, Santiago Marraco, un pleno extraordinario en el Ayuntamiento, y la inauguraciâ”œâ”‚n de este monumento con presencia del alcalde accidental, Antonio Gonzâ”œأ­lez Triviâ”œâ–’o. La Amical de Mauthausen es una asociaciâ”œâ”‚n que agrupa desde 1962 a los exdeportados republicanos (los "espaâ”œâ–’oles rojos") de los campos de concentraciâ”œâ”‚n del nazismo, asâ”œآ، como a los familiares y amigos, tanto de los supervivientes como de los deportados asesinados en los campos. El monumento fue diseâ”œâ–’ado por Fernando Fernâ”œأ­ndez Lâ”œأ­zaro, con unas decrecientes y fracturadas barras en hormigâ”œâ”‚n armado que representan la bandera de Aragâ”œâ”‚n a cuya derecha continuaba un cuerpo sobre el que se colocâ”œâ”‚ una placa con el texto "El Ayuntamiento de Zaragoza en homenaje a los aragoneses confinados en los campos de concentraciâ”œâ”‚n alemanes durante la segunda guerra mundial. Septiembre 1985". Los ajustados plazos de tiempo con que se realizâ”œâ”‚ esta obra impidieron que pudiera completarse con algunos elementos diseâ”œâ–’ados para la misma, que ya no se aâ”œâ–’adieron despuâ”œآ®s. Las reiteradas agresiones fascistas y neonazis a este monumento, pues no permiten mâ”œأ­s memoria histâ”œâ”‚rica que la sectaria y apologâ”œآ®tica suya propia, exclusiva durante mâ”œأ­s de 40 aâ”œâ–’os, ya destruyeron la original placa, que hubo de ser repuesta. Ademâ”œأ­s, y de forma periâ”œâ”‚dica, el monumento debe ser higienizado y limpiado de tâ”œâ”‚xicas pintadas y sâ”œآ،mbolos nazis por el Servicio de Parques y Jardi', 1985, 1985, 1985, 'Anos 80', 'TORRERO', 41.63085700, -0.89434500, '0101000020E610000074EACA67799EECBFF1B913ECBFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48765621818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48765621818.webp', 'https://www.flickr.com/photos/zaragozaantigua/48765621818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24859, 'Av. Amâ”œآ®rica 1978', 'Imagen de la avenida de Amâ”œآ®rica entre la calle Antonio Adrados (antigua de Marcos Sevil, desde 2009 de Juan Francisco Andrâ”œآ®s de Uztarroz), al fondo, y la calle Sancho Ramâ”œآ،rez, en un tramo todavâ”œآ،a caracterizado por antiguas y seriadas parcelas en el lado de los impares (luego mayormente desaparecidas) con sus traseras recayentes a la calle San Josâ”œآ® de Pignatelli (a la izquierda, fuera de plano). Flanquean a los dos carriles habilitados para la circulaciâ”œâ”‚n rodada de bajada, dos carriles para aparcamiento, en zona aparentemente peatonal delimitada por un bordillo, por la cual tambiâ”œآ®n transitaba, de cuando en cuando, algâ”œâ•‘n despistado peatâ”œâ”‚n. Fuente visual: Banco de Imâ”œأ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œآ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'TORRERO', 41.63135600, -0.88540600, '0101000020E610000063D4B5F63E55ECBF1211FE45D0D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32458423993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32458423993.webp', 'https://www.flickr.com/photos/zaragozaantigua/32458423993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24924, 'Mausoleo de Costa 1912', 'Boceto definitivo para el mausoleo de Joaquâ”œآ،n Costa en Zaragoza. Acuarela de Fâ”œآ®lix Lafuente y Manuel Bescâ”œâ”‚s, 1912. Fuente: www.bne.es', 1912, 1912, 1912, 'Anos 10', 'TORRERO', 41.62031800, -0.88575000, '0101000020E6100000F2D24D621058ECBF608F899466CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38978230404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38978230404.webp', 'https://www.flickr.com/photos/zaragozaantigua/38978230404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24968, 'Campo de fâ”œâ•‘tbol de Torrero 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 15/06/1975. "Homenaje a Violeta." Imagen del viejito campo de fâ”œâ•‘tbol de Torrero, las traseras de la porterâ”œآ،a que daba a la calle Monzâ”œâ”‚n. Al fondo, detrâ”œأ­s de lo que hoy es la calle Honoroy Garcâ”œآ،a Condoy, y la chavalerâ”œآ،a encaramada en el muro, el Colegio "El Buen Pastor" y, a pocos metros, el Canal Imperial. Se nota que el campo estâ”œأ­ bastante dejado, a punto de la piqueta, y la naturalizaciâ”œâ”‚n del espacio en forma de vegetaciâ”œâ”‚n es bien aprovechada por su sombra en un dâ”œآ،a de junio ya poco fresco. El evento deportivo es un homenaje al "Leâ”œâ”‚n de Torrero", Josâ”œآ® Luis Violeta, indâ”œآ،gena del barrio y superlativo jugador del Real Zaragoza.', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15260315121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15260315121.webp', 'https://www.flickr.com/photos/zaragozaantigua/15260315121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24969, 'Campo de Torrero 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Enero 1968. Imagen del campo de fâ”œâ•‘tbol de Torrero. Los edificios del fondo, parcelitas incluidas, en la calle Lasierra Purroy.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63069600, -0.88341900, '0101000020E6100000E04735ECF744ECBFE8DB82A5BAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15537925898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15537925898.webp', 'https://www.flickr.com/photos/zaragozaantigua/15537925898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24970, 'Campo de Torrero 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Setiembre 1966. Imagen parcial del estado del campo de Torrero en la segunda mitad de los aâ”œâ–’os 60 del pasado siglo. La captura ha sido realizada desde el câ”œâ”‚rner del fondo sur (que daba a la calle Monzâ”œâ”‚n), mirando hacia la calle Lasierra Purroy, cuyo nâ”¬â•‘ 64 sobresale por encima de "las gradas". De una forma u otra, este espacio seguâ”œآ،a siendo usado para la prâ”œأ­ctica de deportes varios, incluyendo el de la toma de sol como prolongaciâ”œâ”‚n de la cercana piscina.', 1966, 1966, 1966, 'Anos 60', 'TORRERO', 41.62976600, -0.88366900, '0101000020E610000016A6EF350447ECBFFD101B2C9CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15865489700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15865489700.webp', 'https://www.flickr.com/photos/zaragozaantigua/15865489700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24977, 'Campo de fâ”œâ•‘tbol de Torrero 1970', 'Foto: Josâ”œآ® Luis Cintora. Aspecto del campo de fâ”œâ•‘tbol de Torrero (izquierda) utilizado para tomar el sol en verano, con la piscina anexa a la derecha. Fuente: rafaelcastillejo.com', 1970, 1970, 1970, 'Anos 70', 'TORRERO', 41.63069600, -0.88341900, '0101000020E6100000E04735ECF744ECBFE8DB82A5BAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20692443496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20692443496.webp', 'https://www.flickr.com/photos/zaragozaantigua/20692443496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24985, 'Torrero 1974', 'Imagen del antiguo campo de Torrero, como escenario de la final del campeonato de fâ”œâ•‘tbol de equipos de empresas, ganada por la plantilla de la picarraleâ”œâ–’a fâ”œأ­brica "TUSA" a los "Zetaceros". El posado incluye al trâ”œآ،o arbitral, los capitanes de ambos equipos, y una joven de protocolo. Al fondo, la descomunal nueva grada levantada en una parte del lienzo este del campo, recayente a un vial que unos aâ”œâ–’os despuâ”œآ®s serâ”œآ،a denominado Honorio Garcâ”œآ،a Condoy. A la derecha, asoma el colegio "Buen Pastor". Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.63020100, -0.88288500, '0101000020E61000007120240B9840ECBF0874266DAAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30653146521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30653146521.webp', 'https://www.flickr.com/photos/zaragozaantigua/30653146521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24944, 'Parque Grande 1969', 'El sâ”œأ­bado 7 de mayo llegâ”œâ”‚ a Zaragoza la serpiente multicolor de la Vuelta Ciclista a Espaâ”œâ–’a de ese aâ”œâ–’o. Tras un primer sector de etapa cubierto entre Barbastro y Zaragoza, de apenas 121 kilâ”œâ”‚metros, ganado por el belga Raymond Steegmans, y tras un descanso de poco mâ”œأ­s de media hora, comenzâ”œâ”‚ el segundo sector de la etapa, consistente en una contrarreloj individual en un circuito urbano de cuatro kilâ”œâ”‚metros. El ganador fue el francâ”œآ®s Roger Pingeon, a la postre vencedor de la Vuelta. En segundo lugar de la clasificaciâ”œâ”‚n general quedarâ”œأ­ el espaâ”œâ–’ol Luis Ocaâ”œâ–’a, que en la imagen es vitoreado durante su participaciâ”œâ”‚n en la zaragozana pugna contra Cronos, en el paseo de los Bearneses del parque Primo de Rivera. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63297600, -0.89516900, '0101000020E6100000A7936C7539A5ECBF9293895B05D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24086220032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24086220032.webp', 'https://www.flickr.com/photos/zaragozaantigua/24086220032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25078, 'Torrero 1976', 'Como Vicepresidente Segundo del Gobierno, y Ministro de la Gobernaciâ”œâ”‚n del Reino de Espaâ”œâ–’a, Manuel Fraga Iribarne mantuvo su viaje programado a Zaragoza, a pesar de la imprevista dimisiâ”œâ”‚n del Presidente del Gobierno, Carlos Arias Navarro. A la visita a los heridos por la catâ”œأ­strofe explosiva en la factorâ”œآ،a de Butano en Utebo, la participaciâ”œâ”‚n en los actos del bimilenario de la romana fundaciâ”œâ”‚n de Zaragoza, se le sumâ”œâ”‚ un cariâ”œâ–’oso y popular acto "organizado" por la Asociaciâ”œâ”‚n de Cabezas de Familia del barrio de Torrero, en el que estuvo acompaâ”œâ–’ado, entre otros, por el Alcalde de la ciudad, Miguel Merino, y el Gobernador Civil, Manuel Marâ”œآ،a Uriarte Zulueta. En la imagen, Fraga, flanqueado por el Alcalde (izquierda) y por el Gobernador Civil (derecha), en su intervenciâ”œâ”‚n en la "Hermandad del Buen Pastor", sede de la Asociaciâ”œâ”‚n de Cabezas de Familia de Torrero. Apenas un par de dâ”œآ،as despuâ”œآ®s, fue cesado en sus gubernativas funciones. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'TORRERO', 41.62826800, -0.88385100, '0101000020E6100000412E71E48148ECBFC98FF8156BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24087399671.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24087399671.webp', 'https://www.flickr.com/photos/zaragozaantigua/24087399671/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25108, 'Batalla de Zaragoza, 1710', 'Schlacht bei Saragossa, 1710 Sieg â”œâ•‌ber die Galli-Spanier bey Saragossa, Anno 1710, den 20. Augusti Dibujo: Paul Decker Grabador: Johann Jakob Kleinschmidt Editor: Jeremias Wolf Batalla de Zaragoza. Episodio bâ”œآ®lico de la Guerra de Sucesiâ”œâ”‚n Espaâ”œâ–’ola, con victoria de los proaustrias (alemanes, austrâ”œآ،acos, ingleses, holandeses, y espaâ”œâ–’oles) dirigidos por Starhemberg y Stanhope, ante los proborbones (espaâ”œâ–’oles) comandados por de Bay, el 20 de agosto de 1710. Se desarrollâ”œâ”‚ en las estribaciones de los montes de Torrero (Turmwâ”œأ±chterberg). El grabado representa, en primer plano, al victorioso rey Carlos de Austria a caballito, seguido de Hâ”œآ®rcules mamporrero, mientras pisotea una malâ”œآ®fica representaciâ”œâ”‚n del enemigo borbâ”œâ”‚nico. A los pies de los caballos, Zaragoza se entrega al nuevo rey mediante el simbolismo de las llaves de la ciudad, mientras unos representantes municipales (no electos), de los estamentos privilegiados, le rinden sentida pleitesâ”œآ،a, como antes habâ”œآ،an hecho con el rey borbâ”œâ”‚n, y como volverâ”œأ­n a hacer en unos pocos meses. Detrâ”œأ­s del rey austrâ”œآ،aco, la Fama enarbola una banderola en la que se describen, en imperial alemâ”œأ­n, los acontecimientos bâ”œآ®licos. Volando alto, un â”œأ­ngel trompetero anuncia el portentoso evento a los cuatro vientos. Al fondo, una escenificaciâ”œâ”‚n de la batalla. Mâ”œأ­s al fondo, entre humo, Zaragoza y sus torres. Fuente: www.rijksmuseum.nl/nl/collectie/BI-B-FM-073-49', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14815040117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14815040117.webp', 'https://www.flickr.com/photos/zaragozaantigua/14815040117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25117, 'Batalla de Zaragoza 1710', 'Bataille de Saragosse et Plan des environs de Saragosse : [estampe]. Bibliothâ”œآ؟que Nationale de France. Escena bâ”œآ®lica de la Batalla de Zaragoza, en el Barranco de la Muerte, el 20 de agosto de 1710. Al fondo, vista de Zaragoza y la Aljaferâ”œآ،a. En la parte inferior, mapa de Zaragoza y sus alrededores. Mâ”œأ­s informaciâ”œâ”‚n: es.wikipedia.org/wiki/Batalla_de_Zaragoza', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15154195528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15154195528.webp', 'https://www.flickr.com/photos/zaragozaantigua/15154195528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25119, 'Batalla de Zaragoza 1710', 'Batalla de Zaragoza. Kunsthistorisches Museum. Viena. Autor desconocido. La batalla de Zaragoza o batalla del monte Torrero se librâ”œâ”‚ el 20 de agosto de 1710 en el marco de la Guerra de Sucesiâ”œâ”‚n Espaâ”œâ–’ola. En la pintura podemos ver las refriegas en la zona alta del barranco de la Muerte, donde hoy se levanta un centro comercial gigantesco. Fuente visual: es.wikipedia.org/wiki/Batalla_de_Zaragoza', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15238187111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15238187111.webp', 'https://www.flickr.com/photos/zaragozaantigua/15238187111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25121, 'Batalla de Zaragoza 1710', '"Slag bij Zaragoza, 1710", Romeyn de Hooghe, Amsterdam. "De slag bij Zaragoza. Overwinning van de Geallieerden onder Karel III (aartshertog Karel van Oostenrijk) op de Fransen op 20 augustus 1710". (Relaciâ”œâ”‚n exacta de todo lo que sucediâ”œâ”‚ en la victoria cerca de Zaragoza, conseguida por el rey Carlos III, contra el ejâ”œآ®rcito del duque de Anjou el 20 de agosto de 1710). Fuente visual: www.rijksmuseum.nl', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15575839168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15575839168.webp', 'https://www.flickr.com/photos/zaragozaantigua/15575839168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25128, 'Batalla de Zaragoza 1710', '"Den 20 Aug. 1710 heeft het Leger van Kon Carel III by Zaragossa in Arragon, een glorieuse Vict ..." et caetera. Autor: Petrus Schenk. Lugar del grabado: Amsterdam. Fecha: posterior a 1710. Reproduce un mapa de la cuenca media del râ”œآ،o Ebro centrado en Zaragoza, trazado con motivo de la batalla sita en el Barranco de la Muerte de esta localidad, el 20 de agosto de 1710, entre los ejâ”œآ®rcitos del austracista Carlos, y el borbâ”œâ”‚nico Felipe. La ciudad ha sido seâ”œâ–’alada como si de un bâ”œâ•‘nker se tratara, aunque es un convencionalismo de la â”œآ®poca. El medieval muro de râ”œآ®jola daba para lo que daba. Debajo, una escena idealizada del combate. El autor ha optado por una prudente bruma que envuelve la batalla para evitar tener que inventarse el aspecto de Zaragoza, salvo un pedazo de fantâ”œأ­stica torre. Como pie de imagen, una explicaciâ”œâ”‚n en holandâ”œآ®s y latâ”œآ،n de lo sucedido. Fuente: www.cortesaragon.es/', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16469146020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16469146020.webp', 'https://www.flickr.com/photos/zaragozaantigua/16469146020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25130, 'Batalla de Zaragoza 1710', '"The Battle of Sarragossa [sic]" Nathaniel Parr, 1739 Grabado que ilustra la batalla del Barranco de la Muerte entre el archiduque Carlos de Austria (coronado en Viena como rey de Espaâ”œâ–’a en 1703), y el duque Felipe de Anjou (coronado en Madrid como rey de Espaâ”œâ–’a en 1701). Al fondo, representaciâ”œâ”‚n muy lejanamente aproximada de la ciudad de "Sarragossa", delante de la cual las tropas borbâ”œâ”‚nicas se baten en retirada ante la acometida de la caballerâ”œآ،a inglesa mercenaria del austria. Apenas son visibles, pero hay unos carmelitas descalzos subidos en los tejados de su convento de San Joseph, junto al arroyo de la Huerba, mirando con atenciâ”œâ”‚n prâ”œأ­ctica el desenlace bâ”œآ®lico para orientar convenientemente su leal fidelidad al ganador de la batalla. El archiduque Carlos, vencedor de la batalla, cabalga en primer plano como si estuviera de paseo por un bien despejado monte de Torrero. Fuente visual: www.britishmuseum.org/', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17693851185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17693851185.webp', 'https://www.flickr.com/photos/zaragozaantigua/17693851185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25156, 'Barranco de la Muerte 1710', 'Pintura recreando una carga de caballerâ”œآ،a realizada por el 10â”¬â•‘ de Dragones durante la batalla de Zaragoza, a finales del mes de agosto de 1710, en el marco de la Guerra de Sucesiâ”œâ”‚n espaâ”œâ–’ola. A pesar de la buena actuaciâ”œâ”‚n de la caballerâ”œآ،a, a la derecha del campo de batalla, la descomposiciâ”œâ”‚n de las alas izquierda y centro del ejâ”œآ®rcito borbâ”œâ”‚nico derivâ”œâ”‚ en clara derrota tâ”œأ­ctica que supuso la recuperaciâ”œâ”‚n de Zaragoza por el archiduque Carlos, que entrâ”œâ”‚ por segunda vez en la ciudad. Apenas cuatro meses despuâ”œآ®s, y con la destaca participaciâ”œâ”‚n del 10â”¬â•‘ de Dragones, en las batallas de Brihuega y Villaviciosa la guerra dio un nuevo vuelco, definitivo, a favor de Felipe V. Este regimiento de caballerâ”œآ،a sobre el pie, reconocible por su llamativo uniforme amarillo, fue creado en 1709 por Jaime Miguel de Guzmâ”œأ­n Dâ”œأ­valos y Spinola, conde de Pezuela y marquâ”œآ®s de la Mina. Desde 1718, este regimiento de caballerâ”œآ،a es denominado "Lusitania". Fuente visual: "El zurdo", â”œâ”‚leo sobre tabla, Marco Ortolan, 2010, en es.pinterest.com/', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31913066342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31913066342.webp', 'https://www.flickr.com/photos/zaragozaantigua/31913066342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25941, 'Batalla de Zaragoza 1710', 'En Viena puede verse una imagen de la Zaragoza de comienzos del siglo XVIII. Basta con acercarse al convento de los Capuchinos o Cripta Imperial de la Casa Habsburgo, en la Karlsgruft (Cripta de Carlos), donde se halla el sarcâ”œâ”‚fago del emperador Carlos VI. Este Carlos fue pretendiente a la Corona espaâ”œâ–’ola durante la Guerra de Sucesiâ”œâ”‚n Espaâ”œâ–’ola (1700-1711), hasta que la muerte de su hermano le convirtiâ”œâ”‚ en emperador alemâ”œأ­n, dejando el trono espaâ”œâ–’ol expedido a Felipe V. En la imagen, esplendoroso sarcâ”œâ”‚fago de Carlos VI, fallecido en 1740, en cuyo frontal fue tallado en relieve la "Batalla de Zaragoza" de agosto de 1710. A pesar de la relativa importancia de esta batalla, que fue ganada por el ejâ”œآ®rcito del pretendiente austriaco, apenas le dio el control de Zaragoza durante cuatro meses. Esta batalla aparece reseâ”œâ–’ada en el frontal del sepulcro junto a los grandes sâ”œآ،mbolos del Sacro Imperio Romano Germâ”œأ­nico (cetro, espada, Toisâ”œâ”‚n de Oro, Orbe...), y custodiado por cuatro calaveras que portan la corona hâ”œâ•‘ngara de San Wenceslao, la Imperial Germana, la del Sacro Imperio Romano Germâ”œأ­nico, y... la corona de Castilla. El gran relieve frontal recoge el despliegue de tropas en la batalla que tuvo lugar al sureste de Zaragoza el 21 de agosto de 1710, y cuya acciâ”œâ”‚n bâ”œآ®lica mâ”œأ­s destacada transcurriâ”œâ”‚ en el Barranco de la Muerte. Al fondo, amurallada, la ciudad con su extensa colecciâ”œâ”‚n de torres. Fuente visual: www.cuk.ch/articles/5028', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16229583918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16229583918.webp', 'https://www.flickr.com/photos/zaragozaantigua/16229583918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25948, 'Cementerio c.1920', 'Puerta de acceso, desde el exterior del cementerio de Torrero. Fuente: Foto Jesâ”œâ•‘s Cormâ”œأ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'TORRERO', 41.62386200, -0.88765100, '0101000020E6100000D05FE811A367ECBFCC9BC3B5DACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24888246306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24888246306.webp', 'https://www.flickr.com/photos/zaragozaantigua/24888246306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25949, 'Batalla de Zaragoza 1710', 'Imagen con la representaciâ”œâ”‚n de la batalla de Zaragoza de 1710, evento bâ”œآ®lico de la guerra de Sucesiâ”œâ”‚n espaâ”œâ–’ola cuyo desenlace marcâ”œâ”‚ el retorno de la ciudad a la fidelidad del archiduque Carlos de Austria. Este relieve forma parte del frontal del sarcâ”œâ”‚fago del "Kaiser Karl VI", que fue en lo que se convirtiâ”œâ”‚ el archiduque poco tiempo despuâ”œآ®s de esta batalla, cuando las obligaciones familiares le convirtieron en emperador del Sacro Imperio Romano Germâ”œأ­nico, y dejâ”œâ”‚ la aventura espaâ”œâ–’ola en que fue embarcado cuando apenas tenâ”œآ،a 15 aâ”œâ–’os de edad. Se encuentra en la Cripta Imperial de la Casa de Habsburgo, en el convento de los Capuchinos de Viena. La talla recoge el despliegue de tropas austrâ”œآ،acas y borbâ”œâ”‚nicas al sureste de la ciudad a finales de agosto de 1710, en las inmediaciones del antiguo Barranco de la Muerte. Al fondo, a la derecha, en una vista idealizada, la muralla de la ciudad de Zaragoza, tras la que se representa una colecciâ”œâ”‚n de torres de ensueâ”œâ–’o onâ”œآ،rico: la intenciâ”œâ”‚n no era retratar la ciudad, siempre en segundo plano, sino destacar hazaâ”œâ–’as bâ”œآ®licas varias, a mayor gloria del pretendiente austrâ”œآ،aco. Para la realizaciâ”œâ”‚n de esta obra se tomâ”œâ”‚ como referencia la pintura "Batalla de Zaragoza", de autor incierto, hoy en el Kunsthistorisches Museum de Viena. Fuente visual: Bildarchiv Foto Marburg', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26019518720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26019518720.webp', 'https://www.flickr.com/photos/zaragozaantigua/26019518720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25953, 'Cementerio de Torrero 1895', 'Plano de la ampliaciâ”œâ”‚n del Cementerio de Torrero. Ricardo Magdalena, 1895. Fuente: AMZ.', 1895, 1895, 1895, 'Siglo XIX', 'TORRERO', 41.62277600, -0.88844200, '0101000020E61000001492CCEA1D6EECBFEA5DBC1FB7CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32127587996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32127587996.webp', 'https://www.flickr.com/photos/zaragozaantigua/32127587996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25954, 'Cementerio de Torrero 1896', 'Plano del Cementerio de Torrero. Ricardo Magdalena, Zaragoza, septiembre de 1896. Fuente: AMZ.', 1896, 1896, 1896, 'Siglo XIX', 'TORRERO', 41.62306500, -0.88827000, '0101000020E6100000CD920035B56CECBF20240B98C0CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32129129076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32129129076.webp', 'https://www.flickr.com/photos/zaragozaantigua/32129129076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25955, 'Torrero 1911', 'Imagen capturada durante la construcciâ”œâ”‚n de la sepultura de Joaquâ”œآ،n Costa en el cementerio catâ”œâ”‚lico de Torrero, en la ubicaciâ”œâ”‚n escogida por los tenientes de alcalde Marraco e Isâ”œأ­bal, y tras la preceptiva autorizaciâ”œâ”‚n del arzobispo Juan Soldevila y Romero. Despuâ”œآ®s de haber excavado la sepultura en profundidad, los operarios posan durante la fase de revestimiento interno con ladrillo y cemento. Tras ellos, la calle central del campo santo, con una vista parcial del notorio panteâ”œâ”‚n de los canâ”œâ”‚nigos del Cabildo, diseâ”œâ–’ado por Fernando de Yarza. Aunque inicialmente estaba previsto levantar aquâ”œآ، mismo un "magnâ”œآ،fico" mausoleo diseâ”œâ–’ado por el arquitecto municipal Fâ”œآ®lix Navarro Pâ”œآ®rez, su efectiva realizaciâ”œâ”‚n llevâ”œâ”‚ otros derroteros, y ubicaciâ”œâ”‚n. Fuente visual: reportaje fotogrâ”œأ­fico "Entierro de Joaquâ”œآ،n Costa en Zaragoza", de Aurelio Grasa, en Archivo Barboza-Grasa (www.aureliograsa.es/).', 1911, 1911, 1911, 'Anos 10', 'TORRERO', 41.62190900, -0.88814200, '0101000020E61000006E8786C5A86BECBF460BD0B69ACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34379245162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34379245162.webp', 'https://www.flickr.com/photos/zaragozaantigua/34379245162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24959, 'Velâ”œâ”‚dromo de Torrero 1934', '1934. Los terrenos del "Iberia Sport Club", junto a la calle Lasierra Purroy, muy cerca del Canal Imperial, las "graveras", y la Avenida de Amâ”œآ®rica, eran unas instalaciones deportivas de gran nivel que desde 1923 incluâ”œآ،an la â”œâ•‘nica piscina de Zaragoza, ademâ”œأ­s del recordado campo de fâ”œâ•‘tbol de Torrero. En 1928 se sumâ”œâ”‚ una nueva e importante instalaciâ”œâ”‚n: el Velâ”œâ”‚dromo de Torrero, a cuya inauguraciâ”œâ”‚n asistiâ”œâ”‚ el presidente de la "Uniâ”œâ”‚n Velocipâ”œآ®dica Espaâ”œâ–’ola", que asâ”œآ، se llamaba entonces la actual Federaciâ”œâ”‚n Espaâ”œâ–’ola de Ciclismo. En este velâ”œâ”‚dromo tuvieron lugar decenas de pruebas de todo tipo: por supuesto, de pista, pero tambiâ”œآ®n pruebas de carreteras que concluâ”œآ،an allâ”œآ،. Pero la creciente popularidad del balompiâ”œآ® zaragozano influyâ”œâ”‚ negativamente en el ciclismo, de forma que el velâ”œâ”‚dromo empezâ”œâ”‚ a ser utilizado como campo de entrenamiento del primer equipo de balompiâ”œآ® y, desde 1934, el equipo filial del Real Zaragoza (el "Atlâ”œآ®tico Zaragoza") llegâ”œâ”‚ a utilizar el velâ”œâ”‚dromo para jugar allâ”œآ، sus encuentros "de casa". El velâ”œâ”‚dromo, por la fuerza de los acontecimientos, abandonâ”œâ”‚ poco a poco la funciâ”œâ”‚n para la que fue ideado, optando el ciclismo federado por centrarse en el "excursionismo" (actual cicloturismo). La imagen, cortesâ”œآ،a de Sorolla padre, de "Velocâ”œآ،pedos Sorolla", captura un posado en las instalaciones del velâ”œâ”‚dromo de Torrero, cuando aâ”œâ•‘n era usado por los amantes de las dos ruedas de la ciudad. Al fondo, tras la pista y el perimâ”œآ®trico muro (con espectadores encaramados, a modo de tribunas), los â”œأ­rboles de la ribera del cercano Canal Imperial. En la actualidad, en los terrenos de este Velâ”œâ”‚dromo se levantan bloques de viviendas de las calles Lasierra Purroy, Dr. Pascual Oliver, y Honorio Garcâ”œآ،a Condoy.', 1934, 1934, 1934, 'Anos 30', 'TORRERO', 41.63153000, -0.88353000, '0101000020E6100000BD1DE1B4E045ECBFB0389CF9D5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666914568.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666914568.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666914568/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25958, 'Câ”œأ­rcel de Torrero 1996', 'El 31 de mayo de 1996 se convocâ”œâ”‚ una manifestaciâ”œâ”‚n a favor de la recuperaciâ”œâ”‚n de los derechos civiles de los insumisos, mientras el grupo preso en la câ”œأ­rcel de Torrero realizaba una أ”أ‡آ£huelga de frâ”œآ،oأ”أ‡أک. En la imagen, insumisos encarcelados, en el patio de la prisiâ”œâ”‚n, pertrechados con mantas. Las movilizaciones y acciones protestaban por la no eliminaciâ”œâ”‚n de las penas de câ”œأ­rcel por insumisiâ”œâ”‚n en el nuevo Câ”œâ”‚digo Penal durante la etapa de ministro de Justicia e Interior de Juan Alberto Belloch.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62729400, -0.88683400, '0101000020E61000003D635FB2F160ECBF0F7D772B4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50368671706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50368671706.webp', 'https://www.flickr.com/photos/zaragozaantigua/50368671706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25959, 'Plaza de las Canteras 1990', 'Imagen de la plaza de las Canteras realizada desde la inmediata calle de Fray Juliâ”œأ­n Garcâ”œآ®s antes de la reforma de este espacio que aumentâ”œâ”‚ la superficie peatonal, la limitaciâ”œâ”‚n circulatoria a un solo sentido, y la supresiâ”œâ”‚n de la zona de aparcamiento. La reforma incluyâ”œâ”‚, ademâ”œأ­s, un conjunto monumental en memoria del maestro Manuel de Villanueva para dignificar la plaza, que fue ampliado con una escultura en piedra negra de Calatorao que rinde homenaje a la profesiâ”œâ”‚n del cantero, pues la denominaciâ”œâ”‚n de la plaza hacâ”œآ،a referencia precisamente a las canteras que abastecâ”œآ،an a una cercana fâ”œأ­brica de yeso. A la derecha, desaparecido inmueble en el acceso a la calle de Câ”œâ”‚rdoba, donde la antigua barriada de la Esperanza. Al fondo y tras los â”œأ­rboles de la plaza, la avenida de Amâ”œآ®rica. A la izquierda, inicio de la calle de Alicante.', 1990, 1990, 1990, 'Anos 90', 'TORRERO', 41.63160200, -0.88610500, '0101000020E61000007B4E7ADFF85AECBF4A0B9755D8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50371262277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50371262277.webp', 'https://www.flickr.com/photos/zaragozaantigua/50371262277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25960, 'Pinares de Venecia c.1996', 'Imagen de una de las numerosas movilizaciones vecinales convocadas por la Coordinadora Venecia-Torrero-La Paz contra el Tercer Cinturâ”œâ”‚n consistente en el colorido pintado de algunos de los pinos que habrâ”œآ،a que talar en terrenos de los Pinares de Venecia por donde estaba proyectado que pasase el trazado del Tercer Cinturâ”œâ”‚n de ronda. Aunque este tramo del pinar fue denominado "bosque encantado" en referencia del bosque de Oma creado por Agustâ”œآ،n Ibarrola, no hubo magia que detuviera a las excavadoras de la obra.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62543500, -0.89527800, '0101000020E610000056815A0C1EA6ECBF0B630B410ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50516287196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50516287196.webp', 'https://www.flickr.com/photos/zaragozaantigua/50516287196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25961, 'Cementerio de Torrero 1980', 'Tras el 18 de julio de 1936 mâ”œأ­s 600 varones desafectos con el golpe militar y originarios de pueblos de Aragâ”œâ”‚n, Navarra, La Rioja y Soria ribereâ”œâ–’os del râ”œآ،o Ebro se alistaron en el legionario Tercio General Sanjurjo como forma de tratar de escapar a una mâ”œأ­s que probable muerte. Sin embargo, las autoridades militares nacionalistas, ante el riesgo de una posible deserciâ”œâ”‚n masiva decidieron aplicar un castigo ejemplarizante y preventivo: fueron conducidos al campo de maniobras de San Gregorio y, en los primeros dâ”œآ،as del mes de octubre un nâ”œâ•‘mero todavâ”œآ،a sin determinar de ellos fueron asesinados. Sus cuerpos fueron luego trasladados en camiones al cementerio de Torrero, enterrados en una gran fosa comâ”œâ•‘n y sin dejar constancia de ello en los libros de inhumaciones. Cuarenta y tres aâ”œâ–’os despuâ”œآ®s, descendientes navarros y riojanos solicitaron al Ayuntamiento tardofranquista de Zaragoza que se exhumaran sus cuerpos para devolverlos a sus pueblos natales. Se les dio permiso, aunque por sus propios medios y bajo su responsabilidad, y comenzaron la tarea en la manzana 4 del cementerio de Torrero, en una de las conocidas como "zanjas de fusilados". Durante los trabajos, saliâ”œâ”‚ a la luz una zona de zanjas con cerca de 3.000 cadâ”œأ­veres, apilados con y sin caja. Tras las elecciones municipales celebradas pocos meses despuâ”œآ®s, el nuevo Ayuntamiento democrâ”œأ­tico iniciâ”œâ”‚ el estudio de este asunto. En la imagen, familiares de los navarros y riojanos asesinados en esta fosa comâ”œâ•‘n, durante un homenaje fotografiado y publicado en la revista "Interviâ”œâ•‘", en tiempos en que la memoria democrâ”œأ­tica era un asunto privado y con muy poco apoyo institucional y mediâ”œأ­tico.', 1980, 1980, 1980, 'Anos 80', 'TORRERO', 41.62242800, -0.88179200, '0101000020E610000059FB3BDBA337ECBFAE0E80B8ABCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52246629046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52246629046.webp', 'https://www.flickr.com/photos/zaragozaantigua/52246629046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25962, 'Cementerio 1911', 'Imagen capturada en el cementerio catâ”œâ”‚lico de Torrero el dâ”œآ،a en que se trasladaron allâ”œآ، los restos mortales de Joaquâ”œآ،n Costa. Muchas personas que formaban parte de la multitudinaria comitiva que participâ”œâ”‚ en este evento, aprovecharon esa circunstancia para hacer de ese dâ”œآ،a un remedo de la festividad de Todos los Santos, cuando la ciudad de los vivos se vuelca en la ciudad de los muertos. Ese dâ”œآ،a estaba marcado en el calendario como una jornada centrada en el recuerdo a los fallecidos, comenzando con la ceremonia religiosa en la parroquia de referencia, para luego encaminarse (algunos lo hacâ”œآ،an literalmente asâ”œآ،) a pasar el dâ”œآ،a en el cementerio, desde el punto de la maâ”œâ–’ana y hasta la hora de cierre. Allâ”œآ، se procedâ”œآ،a a limpiar la tumba, se la adornaba con flores, coronas y luminarias, y se realizaban las preceptivas oraciones y sufragios en recuerdo de los fallecidos. Al anochecer, la gente regresaba a Zaragoza y algunos terminaban la jornada asistiendo a la representaciâ”œâ”‚n de "Don Juan Tenorio", ese drama religioso-fantâ”œأ­stico tambiâ”œآ®n asociado a la fecha del 1 de noviembre.', 1911, 1911, 1911, 'Anos 10', 'TORRERO', 41.62185800, -0.88733900, '0101000020E610000019E42EC21465ECBFC460FE0A99CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53459502006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53459502006.webp', 'https://www.flickr.com/photos/zaragozaantigua/53459502006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26059, 'Lasierra Purroy c.1927', 'Aâ”œآ®rea visual centrada en el entorno del reciente campo de fâ”œâ•‘tbol de la Sociedad Iberia F.C, sito en la calle de Lasierra Purroy, y complementado con una reglamentaria piscina descubierta, y un velâ”œâ”‚dromo. A la izquierda, parcelas de las antiguas calles de Navarro (luego Doctor Ibâ”œأ­â”œâ–’ez), Vega (luego Juan Cabrero), y J. Marcos (luego, Antonio Adrados), que arrancan en la avenida de Amâ”œآ®rica. A la derecha, eriales y eras varias, en descenso hasta la ribera del Canal Imperial, significativamente reseâ”œâ–’ada por una lineal foresta de plâ”œأ­tanos de sombra y acacias. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1927, 1927, 1927, 'Anos 20', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33782629286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33782629286.webp', 'https://www.flickr.com/photos/zaragozaantigua/33782629286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21757, 'Casa Bergua 1933', 'Imagen de la racionalista y excepcional "casa particular" de Matâ”œآ،as Bergua Olivâ”œأ­n, obra del arquitecto Rafael Bergamâ”œآ،n, en la achaflanada esquina entre el paseo de Ruiseâ”œâ–’ores y el paseo del Canal. La vista ha sido capturada desde el paseo del Canal. Al fondo, a la izquierda, la fâ”œأ­brica de harinas "La Imperial de Aragâ”œâ”‚n". Fuente visual: "Arquitectura" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63423200, -0.89016700, '0101000020E6100000514F1F813F7CECBFD009A1832ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22616016916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22616016916.webp', 'https://www.flickr.com/photos/zaragozaantigua/22616016916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23121, 'Embarcadero del Canal 2006', 'Foto: Marâ”œآ،a Torres-Solanot. Fin de la construcciâ”œâ”‚n de un embarcadero en el Canal Imperial de Aragâ”œâ”‚n, junto a la calle â”œأ¼frica, en junio de 2006. Fue una iniciativa de la Asociaciâ”œâ”‚n de Vecinos de Torrero. En el solar donde estâ”œأ­n almacenados los materiales de construcciâ”œâ”‚n, se inaugurâ”œâ”‚ en mayo de 2011 un pequeâ”œâ–’o edificio diseâ”œâ–’ado por Alejandro San Felipe, que alberga la terraza-bar El corazâ”œâ”‚n verde. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'TORRERO', 41.63111000, -0.89163200, '0101000020E6100000742502D53F88ECBFDB166536C8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31122424394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31122424394.webp', 'https://www.flickr.com/photos/zaragozaantigua/31122424394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25002, 'Residencia Estudiantes 1926', 'La innovadora Residencia de Estudiantes de la Universidad de Zaragoza, con proyecto del arquitecto Teodoro Râ”œآ،os, comenzâ”œâ”‚ a funcionar en el curso 1924-25, aunque su inauguraciâ”œâ”‚n oficial fue retrasada hasta febrero de 1925, para incluirla en los actos del "Dâ”œآ،a de la Universidad" y hacerlo coincidir con la presencia real de Alfonso XIII. Asâ”œآ، se hacâ”œآ،an las cosas durante la dictadura de Primo de Rivera. Poco despuâ”œآ®s se le dio el acadâ”œآ®mico nombre de "Colegio Mayor del Fundador Don Pedro Cerbuna", con Miguel Alluâ”œآ® como su primer director (hasta 1927). Esta Residencia fue construida en el Paseo de Ruiseâ”œâ–’ores nâ”¬â•‘ 23, justo donde la bifurcaciâ”œâ”‚n con el Camino Viejo de Cuarte. Su edificio principal era de planta rectangular en tres alturas, junto al Jardâ”œآ،n Botâ”œأ­nico. Entre sus instalaciones habâ”œآ،a frontâ”œâ”‚n para juego de pelota, piscina, pista de "tennis", campo de "Foot-ball"... Fue clausurado en 1936, y ya no se recuperâ”œâ”‚. En los aâ”œâ–’os 60 fue derribado y sobre su solar se construirâ”œأ­ el nuevo Instituto Femenino Miguel Servet, con proyecto de Regino Borobio, que serâ”œأ­ inaugurado en 1965. En la imagen, aspecto de la "fachada del mediodâ”œآ،a", destacando el poderoso torreâ”œâ”‚n que permitâ”œآ،a unas vistas muy apreciables. El paseo de Ruiseâ”œâ–’ores queda a la izquierda, donde estaba la entrada. El Jardâ”œآ،n Botâ”œأ­nico queda detrâ”œأ­s del edificio. Fuente visual: Revista "Aragâ”œâ”‚n", nâ”¬â•‘ 4.', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.63538700, -0.88994600, '0101000020E6100000AF97A608707AECBFDBA6785C54D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20541642466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20541642466.webp', 'https://www.flickr.com/photos/zaragozaantigua/20541642466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25006, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Vista parcial del edificio de la Residencia de Estudiantes de la Universidad de Zaragoza, oficialmente denominada "Colegio Mayor de Cerbuna", en una imagen capturada desde su ingreso en el nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores, donde estaba radicada.', 1931, 1931, 1931, 'Anos 30', 'TORRERO', 41.63532000, -0.88995600, '0101000020E610000092205C01857AECBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25788523007.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25788523007.webp', 'https://www.flickr.com/photos/zaragozaantigua/25788523007/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
